from machine import Pin, ADC
import network
import time
from umqtt.simple import MQTTClient

# WiFi credentials
SSID = 'your_wifi_ssid'
PASSWORD = 'your_wifi_password'

# MQTT broker details
BROKER_IP = 'broker_ip_address'
CLIENT_ID = 'esp32_client'
TOPIC = 'sensors/temp'

# Connect to WiFi
def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect(SSID, PASSWORD)
    while not wlan.isconnected():
        time.sleep(1)
    print('Connected to WiFi')

# Read temperature from sensor
def read_temperature():
    adc = ADC(Pin(34))
    adc.atten(ADC.ATTN_11DB)
    adc.width(ADC.WIDTH_12BIT)
    raw_value = adc.read()
    temperature = (raw_value / 4095.0) * 100  # Example conversion
    return temperature

# Publish temperature data to MQTT broker
def publish_temperature(client):
    temperature = read_temperature()
    client.publish(TOPIC, str(temperature))
    print(f'Published: {temperature} to {TOPIC}')

# Main function
def main():
    connect_wifi()
    client = MQTTClient(CLIENT_ID, BROKER_IP)
    client.connect()
    try:
        while True:
            publish_temperature(client)
            time.sleep(10)  # Publish every 10 seconds
    finally:
        client.disconnect()

if __name__ == '__main__':
    main()